"""Tokenisation helpers for textstats."""

import re

PUNCT = ".,;:!?\"'()"


def tokenize(text):
    """Split text into raw word tokens."""
    # Split on any whitespace (spaces, tabs, newlines)
    return text.split()


def clean(token):
    """Strip surrounding punctuation from a token."""
    return token.strip(PUNCT)

